var doc = Rhino.RhinoDoc.ActiveDoc;
var xform = Rhino.Geometry.Transform.Mirror(Rhino.Geometry.Plane.WorldYZ);
int mirrored = 0;
foreach (var obj in doc.Objects.GetSelectedObjects(false, false))
{
    if (doc.Objects.Transform(obj.Id, xform, false) != Guid.Empty) mirrored++;
}
doc.Views.Redraw();
return new { mirrored = mirrored, plane = "WorldYZ" };
